787→    private static void setFollowStatusForPosts(long blogId, long feedId, boolean isFollowed) {
788→        if (blogId == 0 && feedId == 0) {
789→            return;
790→        }
791→
792→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
793→        db.beginTransaction();
794→        try {
795→            if (blogId != 0) {
796→                String sql = "UPDATE tbl_posts SET is_followed=" + SqlUtils.boolToSql(isFollowed)
797→                             + " WHERE blog_id=?";
798→                db.execSQL(sql, new String[]{Long.toString(blogId)});
799→            } else {
800→                String sql = "UPDATE tbl_posts SET is_followed=" + SqlUtils.boolToSql(isFollowed)
801→                             + " WHERE feed_id=?";
802→                db.execSQL(sql, new String[]{Long.toString(feedId)});
803→            }
804→
805→
806→            // if blog/feed is no longer followed, remove its posts tagged with "Followed Sites" or "P2"
807→            if (!isFollowed) {
808→                if (blogId != 0) {
809→                    db.delete("tbl_posts", "blog_id=? AND (tag_name=? OR tag_name=?)",
