840→        // if the post has an excerpt (which should always be the case), store it as the full text
841→        // with a link to the full article
842→        if (post.hasExcerpt()) {
843→            AppLog.w(AppLog.T.READER, "reader post table > max text exceeded, storing excerpt");
844→            return "<p>" + post.getExcerpt() + "</p>"
845→                   + String.format("<p style='text-align:center'><a href='%s'>%s</a></p>",
