1260→        boolean hasPerformedSearch = !TextUtils.isEmpty(mCurrentSearchQuery);
1261→
1262→        toggleJetpackBannerIfEnabled(true, false);
1263→
1264→        // prevents suggestions from being shown after the search view has been collapsed
1265→        if (!isSearching()) {
1266→            return;
1267→        }
1268→
1269→        // prevents suggestions from being shown above search results after configuration changes
1270→        if (mWasPaused && hasPerformedSearch) {
1271→            return;
1272→        }
1273→
1274→        if (!hasQuery || !hasPerformedSearch) {
1275→            // clear posts and sites so only the suggestions or the empty view are visible
1276→            getPostAdapter().clear();
1277→            getSiteSearchAdapter().clear();
1278→
1279→            hideSearchTabs();
1280→
